code.state_machine:
// Estado e fases
let state: 'p1' | 'splash' | 'p2' | 'idle' = 'p1';
let lastStateChange = performance.now();
let percentage = 0;

const DURATIONS = { p1: 800, splash: 800, p2: 800, idle: 1000 };

const tick = (now: number) => {
  const elapsed = now - lastStateChange;

  switch (state) {
    case 'p1': {
      percentage = Math.min(0.5, (elapsed / DURATIONS.p1) * 0.5);
      animateGradient(percentage);
      if (percentage < 0.4) nodeStack.classList.add('active');
      else nodeStack.classList.remove('active');
      if (elapsed >= DURATIONS.p1) {
        beamPaths.forEach(p => p.style.opacity = '0');
        splash.classList.add('animate');
        state = 'splash'; lastStateChange = now;
      }
      break;
    }
    case 'splash': {
      if (elapsed >= DURATIONS.splash) {
        beamPaths.forEach(p => p.style.opacity = '1');
        splash.classList.remove('animate');
        state = 'p2'; lastStateChange = now;
      }
      break;
    }
    case 'p2': {
      percentage = 0.5 + Math.min(0.5, ((elapsed / DURATIONS.p2) * 0.5));
      animateGradient(percentage);
      if (percentage > 0.6) nodeShield.classList.add('active');
      if (elapsed >= DURATIONS.p2) {
        nodeShield.classList.remove('active');
        state = 'idle'; lastStateChange = now;
      }
      break;
    }
    case 'idle': {
      if (elapsed >= DURATIONS.idle) {
        percentage = 0; state = 'p1'; lastStateChange = now;
      }
      break;
    }
  }
  requestAnimationFrame(tick);
};

code.gradient_animation:
// Mover a janela de luz ao longo do path
const animateGradient = (pct: number) => {
  const center = pct * 100; // 0-100 em percentual
  const half = 5;           // largura da janela de luz
  gradient.setAttribute('x1', `${center - half}%`);
  gradient.setAttribute('x2', `${center + half}%`);
  gradient.setAttribute('y1', '0%');
  gradient.setAttribute('y2', '0%');
};

